/**
 * Calculates combinations C(n, k) modulo MOD.
 * @param {bigint} n_val 
 * @param {bigint} k_val 
 * @returns {bigint}
 */
function combinations(n_val, k_val) {
    const MOD = 1000000007n;

    if (k_val < 0n || k_val > n_val) {
        return 0n;
    }
    if (k_val === 0n || k_val === n_val) {
        return 1n;
    }
    if (k_val > n_val / 2n) {
        k_val = n_val - k_val;
    }

    // Precompute factorials and inverse factorials might be faster for many queries, 
    // but for a single call, direct calculation with modular inverse is fine.

    // Calculate numerator: n * (n-1) * ... * (n-k+1)
    let numerator = 1n;
    for (let i = 0n; i < k_val; i++) {
        numerator = (numerator * (n_val - i)) % MOD;
    }

    // Calculate denominator: k!
    let denominator = 1n;
    for (let i = 1n; i <= k_val; i++) {
        denominator = (denominator * i) % MOD;
    }

    // Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
    const power = (base, exp) => {
        let res = 1n;
        base %= MOD;
        while (exp > 0n) {
            if (exp % 2n === 1n) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp /= 2n;
        }
        return res;
    };

    const invDenominator = power(denominator, MOD - 2n);

    return (numerator * invDenominator) % MOD;
}


/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @returns {number}
 */
function solve(n, pos, k) {
    const MOD = 1000000007;

    // Number of people to the left of pos (indices 0 to pos-1)
    const left_count = pos; 
    // Number of people to the right of pos (indices pos+1 to n-1)
    const right_count = n - 1 - pos; 

    // The person at pos can choose 'L' or 'R' (2 options), which doesn't affect the count k.
    // We need to find the number of ways to choose directions for the other n-1 people
    // such that exactly k people are visible.

    // Let l be the number of people from the left visible to pos.
    // A person i < pos is visible iff they choose 'L'. There are 'left_count' such people.
    // Let r be the number of people from the right visible to pos.
    // A person i > pos is visible iff they choose 'R'. There are 'right_count' such people.
    // We need l + r = k.

    // l can range from 0 to left_count.
    // r can range from 0 to right_count.

    let total_ways_for_others = 0n;

    for (let l = 0; l <= left_count; l++) {
        // We need r = k - l
        const r = k - l;

        // Check if r is valid
        if (r >= 0 && r <= right_count) {
            // Number of ways to choose l 'L's among left_count people: C(left_count, l)
            const ways_left = combinations(BigInt(left_count), BigInt(l));

            // Number of ways to choose r 'R's among right_count people: C(right_count, r)
            const ways_right = combinations(BigInt(right_count), BigInt(r));

            // Total ways for this pair (l, r)
            const ways_current = (ways_left * ways_right) % BigInt(MOD);

            total_ways_for_others = (total_ways_for_others + ways_current) % BigInt(MOD);
        }
    }

    // The person at pos has 2 independent choices ('L' or 'R').
    // Total answer = (ways for others) * 2
    const result = (total_ways_for_others * 2n) % BigInt(MOD);

    return Number(result);
}

